const parseNetWorthTier = (worth) => {
  const num = parseFloat(worth.replace(/[$,+]/g, ""));
  const millions = /[bB]/.test(worth) ? num * 1000 : num;
  if (millions >= 1000) return "$1B+";
  if (millions >= 500)  return "$500M+";
  if (millions >= 100)  return "$100M+";
  return "$50M+";
};

